import React from "react";

export type IconSize = 20 | 24 | 48;

export type IconProps = {
  size?: IconSize;
  className?: string;
  "aria-label"?: string;
};

type PathMap = Record<IconSize, string>;

type Icon2FaPathMap = Record<IconSize, { shield: string; cross: string }>;

function renderIcon(
  size: IconSize,
  paths: PathMap,
  className: string | undefined,
  ariaLabel: string | undefined,
  name: string,
) {
  const classes = ["tt-icon", `tt-icon--${name}`, `tt-icon--size-${size}`, className]
    .filter(Boolean)
    .join(" ");
  return (
    <svg
      className={classes}
      width={size}
      height={size}
      viewBox={`0 0 ${size} ${size}`}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      role={ariaLabel ? "img" : undefined}
      aria-label={ariaLabel}
      aria-hidden={ariaLabel ? undefined : true}
    >
      <path d={paths[size]} fill="currentColor" />
    </svg>
  );
}

