export function FavouriteIcon({ size = 20, className, "aria-label": ariaLabel }: IconProps) {
  return renderIcon(size, favouritePaths, className, ariaLabel, "favourite");
}

export function FlagIcon({ size = 20, className, "aria-label": ariaLabel }: IconProps) {
  return renderIcon(size, flagPaths, className, ariaLabel, "flag");
}

export function LogoutIcon({ size = 20, className, "aria-label": ariaLabel }: IconProps) {
  return renderIcon(size, logoutPaths, className, ariaLabel, "logout");
}

export function NotificationIcon({ size = 20, className, "aria-label": ariaLabel }: IconProps) {
  return renderIcon(size, notificationPaths, className, ariaLabel, "notification");
}

export function ProfileIcon({ size = 20, className, "aria-label": ariaLabel }: IconProps) {
  return renderIcon(size, profilePaths, className, ariaLabel, "profile");
}

export function TwoFaIcon({ size = 20, className, "aria-label": ariaLabel }: IconProps) {
  const paths = twoFaPaths[size];
  const classes = ["tt-icon", "tt-icon--2fa", `tt-icon--size-${size}`, className]
    .filter(Boolean)
    .join(" ");
  return (
    <svg
      className={classes}
      width={size}
      height={size}
      viewBox={`0 0 ${size} ${size}`}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      role={ariaLabel ? "img" : undefined}
      aria-label={ariaLabel}
      aria-hidden={ariaLabel ? undefined : true}
    >
      <path d={paths.shield} fill="currentColor" />
      <path d={paths.cross} fill="currentColor" />
    </svg>
  );
}

type IconPath = { d: string; fillRule?: "evenodd" | "nonzero"; clipRule?: "evenodd" | "nonzero" };
type MultiPathMap = Record<IconSize, IconPath[]>;

function renderLibraryIcon(
  name: string,
  size: IconSize,
  className: string | undefined,
  ariaLabel: string | undefined,
) {
  const paths = LIBRARY_PATHS[name][size];
  const classes = ["tt-icon", `tt-icon--${name}`, `tt-icon--size-${size}`, className]
    .filter(Boolean)
    .join(" ");
  return (
    <svg
      className={classes}
      width={size}
      height={size}
      viewBox={`0 0 ${size} ${size}`}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      role={ariaLabel ? "img" : undefined}
      aria-label={ariaLabel}
      aria-hidden={ariaLabel ? undefined : true}
    >
      {paths.map((p, i) => (
        <path
          key={i}
          d={p.d}
          fill="currentColor"
          fillRule={p.fillRule}
          clipRule={p.clipRule}
        />
      ))}
    </svg>
  );
}

